    94→/// Helper to write a simple PCAP file.
    95→fn write_pcap_file(path: &PathBuf, packets: &[Vec<u8>]) {
    96→    use std::io::Write;
    97→
    98→    let mut file = File::create(path).unwrap();
    99→
   100→    // PCAP global header
   101→    let header = [
   102→        0xd4, 0xc3, 0xb2, 0xa1, // Magic number (little-endian)
   103→        0x02, 0x00, // Version major
   104→        0x04, 0x00, // Version minor
   105→        0x00, 0x00, 0x00, 0x00, // Timezone offset
   106→        0x00, 0x00, 0x00, 0x00, // Timestamp accuracy
   107→        0xff, 0xff, 0x00, 0x00, // Snaplen (65535)
   108→        0x01, 0x00, 0x00, 0x00, // Link-layer type (Ethernet)
   109→    ];
   110→    file.write_all(&header).unwrap();
   111→
   112→    // Write packets
   113→    let mut ts_sec = 1700000000u32;
   114→    let ts_usec = 0u32;
   115→
   116→    for packet in packets {
   117→        ts_sec += 1; // Increment timestamp
   118→
   119→        // Packet header
   120→        file.write_all(&ts_sec.to_le_bytes()).unwrap(); // Timestamp seconds
   121→        file.write_all(&ts_usec.to_le_bytes()).unwrap(); // Timestamp microseconds
   122→        file.write_all(&(packet.len() as u32).to_le_bytes())
   123→            .unwrap(); // Included length
   124→        file.write_all(&(packet.len() as u32).to_le_bytes())
   125→            .unwrap(); // Original length
   126→
   127→        // Packet data
   128→        file.write_all(packet).unwrap();
   129→    }
   130→
   131→    file.flush().unwrap();
   132→}
