   426→fn test_pipeline_timestamp_propagation() {
   427→    // WS-3.4: Assert TCP events have capture-time timestamps, not wall-clock
   428→    let temp_dir = TempDir::new().unwrap();
   429→    let pcap_path = temp_dir.path().join("test_ts.pcap");
   430→
   431→    // Create TCP segment with known timestamp
   432→    let packet = create_tcp_segment(
   433→        [192, 168, 1, 1],
   434→        [10, 0, 0, 1],
   435→        12345,
   436→        80,
   437→        1000,
   438→        0,
   439→        TcpFlags {
   440→            syn: false,
   441→            ack: true,
   442→            fin: true,
   443→            rst: false,
   444→            psh: true,
   445→        },
   446→        b"test_data",
   447→    );
   448→
   449→    // Write PCAP with specific timestamp (2023-11-01 00:00:00 = 1698796800)
   450→    let pcap_timestamp_sec = 1698796800u32;
   451→    let pcap_timestamp_usec = 123456u32;
   452→
   453→    use std::io::Write;
   454→    let mut file = std::fs::File::create(&pcap_path).unwrap();
   455→
   456→    // PCAP global header
   457→    let header = [
   458→        0xd4, 0xc3, 0xb2, 0xa1, // Magic number (little-endian)
   459→        0x02, 0x00, // Version major
   460→        0x04, 0x00, // Version minor
   461→        0x00, 0x00, 0x00, 0x00, // Timezone offset
   462→        0x00, 0x00, 0x00, 0x00, // Timestamp accuracy
   463→        0xff, 0xff, 0x00, 0x00, // Snaplen (65535)
   464→        0x01, 0x00, 0x00, 0x00, // Link-layer type (Ethernet)
   465→    ];
   466→    file.write_all(&header).unwrap();
   467→
   468→    // Packet header
   469→    file.write_all(&pcap_timestamp_sec.to_le_bytes()).unwrap();
   470→    file.write_all(&pcap_timestamp_usec.to_le_bytes()).unwrap();
   471→    file.write_all(&(packet.len() as u32).to_le_bytes()).unwrap();
   472→    file.write_all(&(packet.len() as u32).to_le_bytes()).unwrap();
   473→    file.write_all(&packet).unwrap();
   474→    file.flush().unwrap();
   475→    drop(file);
   476→
   477→    // Process through pipeline
   478→    let mut adapter = PcapCaptureAdapter::new(pcap_path, None);
   479→    let events: Vec<_> = adapter.ingest().collect();
   480→
   481→    assert!(!events.is_empty(), "Should produce at least one event");
   482→
   483→    let event = events[0].as_ref().expect("Event should be Ok");
   484→
   485→    // Calculate expected timestamp in nanoseconds
   486→    let expected_ns = (pcap_timestamp_sec as u64) * 1_000_000_000 + (pcap_timestamp_usec as u64) * 1_000;
   487→
   488→    assert_eq!(
   489→        event.timestamp.as_nanos(),
   490→        expected_ns,
   491→        "Event timestamp should match PCAP capture time, not wall-clock"
   492→    );
   493→}
