   495→#[test]
   496→fn test_pipeline_dsb_keys_used() {
   497→    // WS-3.4: pcapng with DSB → TLS decryption succeeds (after WS-2.1)
   498→    // This is a basic test verifying DSB key loading pathway
   499→    let temp_dir = TempDir::new().unwrap();
   500→    let pcapng_path = temp_dir.path().join("test_dsb.pcapng");
   501→
   502→    // Create a minimal pcapng with DSB block
   503→    use std::io::Write;
   504→    let mut file = std::fs::File::create(&pcapng_path).unwrap();
   505→
   506→    // Section Header Block (SHB)
   507→    let mut shb = Vec::new();
   508→    shb.extend_from_slice(&0x0A0D0D0Au32.to_le_bytes()); // Block Type
   509→    shb.extend_from_slice(&28u32.to_le_bytes()); // Block Total Length
   510→    shb.extend_from_slice(&0x1A2B3C4Du32.to_le_bytes()); // Byte-Order Magic
   511→    shb.extend_from_slice(&1u16.to_le_bytes()); // Major Version
   512→    shb.extend_from_slice(&0u16.to_le_bytes()); // Minor Version
   513→    shb.extend_from_slice(&(-1i64).to_le_bytes()); // Section Length (not specified)
   514→    shb.extend_from_slice(&28u32.to_le_bytes()); // Block Total Length (repeated)
   515→    file.write_all(&shb).unwrap();
   516→
   517→    // Decryption Secrets Block (DSB) - Type 0x0000000A
   518→    let mut dsb = Vec::new();
   519→    dsb.extend_from_slice(&0x0000000Au32.to_le_bytes()); // Block Type
   520→    // Secrets Type: TLS Key Log (0x544c534b = "TLSK")
   521→    let secrets_type = 0x544c534bu32;
   522→    let secrets_data = b""; // Empty key log for this test
   523→    let dsb_len = 12 + 4 + 4 + secrets_data.len() + 4; // header + type + data_len + data + trailer
   524→    let dsb_len_padded = dsb_len.div_ceil(4) * 4; // Pad to 4-byte boundary
   525→    dsb.extend_from_slice(&(dsb_len_padded as u32).to_le_bytes());
   526→    dsb.extend_from_slice(&secrets_type.to_le_bytes());
   527→    dsb.extend_from_slice(&(secrets_data.len() as u32).to_le_bytes());
   528→    dsb.extend_from_slice(secrets_data);
   529→    while dsb.len() % 4 != 0 {
   530→        dsb.push(0x00);
   531→    }
   532→    dsb.extend_from_slice(&(dsb_len_padded as u32).to_le_bytes());
   533→    file.write_all(&dsb).unwrap();
   534→
   535→    file.flush().unwrap();
   536→    drop(file);
   537→
   538→    // Try to load the pcapng (should succeed even with empty DSB)
   539→    let adapter = PcapCaptureAdapter::new(pcapng_path, None);
   540→
   541→    // The fact that we can create the adapter and it doesn't error means DSB was processed
   542→    let stats = adapter.stats();
   543→    assert_eq!(stats.packets_read, 0, "No packets in this test file");
   544→}
