   105→/// Creates a pcapng file with embedded TLS keys (DSB).
   106→fn create_test_pcapng_with_dsb() -> NamedTempFile {
   107→    let mut file = NamedTempFile::new().unwrap();
   108→
   109→    // Section Header Block (SHB)
   110→    file.write_all(&0x0a0d0d0au32.to_le_bytes()).unwrap();
   111→    file.write_all(&28u32.to_le_bytes()).unwrap();
   112→    file.write_all(&0x1a2b3c4du32.to_le_bytes()).unwrap();
   113→    file.write_all(&1u16.to_le_bytes()).unwrap();
   114→    file.write_all(&0u16.to_le_bytes()).unwrap();
   115→    file.write_all(&(-1i64).to_le_bytes()).unwrap();
   116→    file.write_all(&28u32.to_le_bytes()).unwrap();
   117→
   118→    // Interface Description Block (IDB)
   119→    file.write_all(&1u32.to_le_bytes()).unwrap();
   120→    file.write_all(&20u32.to_le_bytes()).unwrap();
   121→    file.write_all(&1u16.to_le_bytes()).unwrap();
   122→    file.write_all(&0u16.to_le_bytes()).unwrap();
   123→    file.write_all(&65535u32.to_le_bytes()).unwrap();
   124→    file.write_all(&20u32.to_le_bytes()).unwrap();
   125→
   126→    // Decryption Secrets Block (DSB)
   127→    // Use a proper 48-byte (96 hex char) master secret for TLS 1.2
   128→    let key_log = "CLIENT_RANDOM 0123456789ABCDEF0123456789ABCDEF0123456789ABCDEF0123456789ABCDEF FEDCBA9876543210FEDCBA9876543210FEDCBA9876543210FEDCBA9876543210FEDCBA9876543210FEDCBA9876543210\n";
   129→    let key_log_bytes = key_log.as_bytes();
   130→    let padding = (4 - (key_log_bytes.len() % 4)) % 4;
   131→    let padded_len = key_log_bytes.len() + padding;
   132→
   133→    // pcapng Block Total Length includes ALL bytes from block_type through trailing length:
   134→    // block_type(4) + block_total_length(4) + secrets_type(4) + secrets_length(4) + padded_data + block_total_length(4)
   135→    let dsb_total_len = 4 + 4 + 4 + 4 + padded_len + 4;
   136→
   137→    // Block Type: 0x0000000a (DSB)
   138→    file.write_all(&0x0au32.to_le_bytes()).unwrap();
   139→    // Block Total Length
   140→    file.write_all(&(dsb_total_len as u32).to_le_bytes()).unwrap();
   141→    // Secrets Type: 0x544c534b ("TLSK")
   142→    file.write_all(&0x544c534bu32.to_le_bytes()).unwrap();
   143→    // Secrets Length (unpadded)
   144→    file.write_all(&(key_log_bytes.len() as u32).to_le_bytes()).unwrap();
   145→    // Secrets Data
   146→    file.write_all(key_log_bytes).unwrap();
   147→    // Padding to 4-byte boundary
   148→    if padding > 0 {
   149→        file.write_all(&vec![0u8; padding]).unwrap();
   150→    }
   151→    // Block Total Length (repeated)
   152→    file.write_all(&(dsb_total_len as u32).to_le_bytes()).unwrap();
   153→
   154→    file.flush().unwrap();
   155→    file.as_file().sync_all().unwrap();
   156→    file
   157→}
