   159→#[test]
   160→fn test_read_pcap_legacy() {
   161→    let pcap_file = create_test_pcap();
   162→    let mut reader = PcapFileReader::open(pcap_file.path()).unwrap();
   163→
   164→    let packets = reader.read_all_packets().unwrap();
   165→
   166→    assert_eq!(packets.len(), 1, "should read exactly one packet");
   167→    assert_eq!(packets[0].linktype, 1, "linktype should be Ethernet (1)");
   168→    assert_eq!(packets[0].timestamp_us, 1000000 * 1_000_000 + 500000, "timestamp should match");
   169→    assert_eq!(packets[0].data, b"Hello PCAP", "packet data should match");
   170→}
   171→
   172→#[test]
   173→fn test_read_pcapng() {
   174→    let pcapng_file = create_test_pcapng();
